PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX ceonq: <http://w3id.org/CEON/ontology/quantity/>
PREFIX dqv: <http://www.w3.org/ns/dqv#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX afn: <http://jena.apache.org/ARQ/function#>

SELECT ?elClass ?elLabel ?v_best ?v_low ?v_high (GROUP_CONCAT(?scoreStr; separator="|") AS ?scores) WHERE {
  ?mag rdfs:label ?ml . FILTER(?ml = "elvElectricMotor_magnetAlloysNdFeB__V0301030103"@en)
  ?mag futuram:hasCompositionStatement ?stmt .
  ?stmt futuram:hasPartRelation ?pr .
  ?pr futuram:refersTo ?el .
  ?el a ?elClass .
  ?elClass rdfs:subClassOf* <http://purl.obolibrary.org/obo/CHEBI_33321> .
  ?el rdfs:label ?elLabel .
  ?pr futuram:hasQuantity ?qi .
  ?qi futuram:hasBestValue [ qudt:numericValue ?v_best ; qudt:unit ?uBest ] .
  OPTIONAL { ?qi ceonq:hasMinimalValueIncludedOfInterval [ qudt:numericValue ?v_low ; qudt:unit ?uLow ] }
  OPTIONAL { ?qi ceonq:hasMaximalValueIncludedOfInterval [ qudt:numericValue ?v_high ; qudt:unit ?uHigh ] }
  OPTIONAL {
    ?pr dqv:hasQualityMeasurement ?qm .
    ?qm dqv:isMeasurementOf ?met ;
        dqv:value ?score .
    OPTIONAL { ?met rdfs:label ?metLabel }
    BIND(CONCAT(STR(?metLabel), "=", STR(?score)) AS ?scoreStr)
  }
} GROUP BY ?elClass ?elLabel ?v_best ?v_low ?v_high ?uBest ?uLow ?uHigh

