       || CONTAINS(LCASE(STR(?label)),   "vw")   || CONTAINS(LCASE(STR(?comment)), "vw")
       || CONTAINS(LCASE(STR(?label)),   "volkswagen") || CONTAINS(LCASE(STR(?comment)), "volkswagen") )
}
ORDER BY ?label
LIMIT 200

